let state=JSON.parse(localStorage.getItem('aguiaV23')||'{"checked":{},"money":{},"xp":0,"cateDone":{},"catePage":0,"cateXP":0,"cateFavorites":[],"journeyIndex":0,"piggy":{"free":0,"saved":0,"charity":0},"aiPlan":"","seenQuestions":{},"grades":null,"academyStats":{},"lastOCR":""}');
if(!state.grades) state.grades=defaultGrades;
if(!state.academyStats) state.academyStats={};
function save(){localStorage.setItem('aguiaV23',JSON.stringify(state))}
function iso(d){return d.toISOString().slice(0,10)} function today(){return iso(new Date())} function money(n){return 'R$ '+Number(n).toFixed(0)} function plan(d){return plans[d.getDay()]} function tid(d,i){return iso(d)+'-'+i}
function stats(d=new Date()){let p=plan(d),done=0;p[3].forEach((_,i)=>{if(state.checked[tid(d,i)])done++});return{done,total:p[3].length,pct:Math.round(done/p[3].length*100),complete:done===p[3].length}}
function avg(arr){return arr.reduce((a,b)=>a+Number(b||0),0)/4}
function criticalSubject(){return Object.entries(state.grades||defaultGrades).map(([s,arr])=>[s,avg(arr)]).sort((a,b)=>a[1]-b[1])[0][0]}
function weakAcademySubject(){let rows=Object.entries(state.academyStats||{}).filter(([s,v])=>(v.total||0)>0).map(([s,v])=>[s,(v.correct||0)/(v.total||1)]); if(!rows.length) return null; return rows.sort((a,b)=>a[1]-b[1])[0][0];}
function smartPriority(){let c=criticalSubject(); if(questionBank[c]) return c; return weakAcademySubject() || 'Matemática';}
function weekMoneyTotal(){return Object.values(state.money).reduce((a,b)=>a+b,0)}
function switchTab(tab){document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));document.getElementById(tab).classList.add('active');document.querySelectorAll('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));renderAll()}
enter.onclick=()=>{if(pass.value===PASSWORD){localStorage.setItem('unlockedV23','yes');lock.classList.add('hidden');app.classList.remove('hidden');switchTab('journey')}else alert('Senha incorreta')};if(localStorage.getItem('unlockedV23')==='yes'){lock.classList.add('hidden');app.classList.remove('hidden');setTimeout(()=>switchTab('journey'),0)}
function saturdaysOfYear(){let y=new Date().getFullYear(),d=new Date(y,0,1),arr=[];while(d.getFullYear()===y){if(d.getDay()===6)arr.push(new Date(d));d.setDate(d.getDate()+1)}return arr.slice(0,52)}
function cateWeekIndex(date=new Date()){let sats=saturdaysOfYear();let idx=sats.findIndex(s=>iso(s)>=iso(date));return idx<0?51:idx}
function cateDoneCount(){return Object.keys(state.cateDone).length}
function renderMission(){let d=new Date(),p=plan(d),s=stats(d);todayTitle.textContent=p[0]+' — '+p[1];tasks.innerHTML=p[3].map((t,i)=>`<label class="task"><input type="checkbox" data-id="${tid(d,i)}" ${state.checked[tid(d,i)]?'checked':''}><span><b>${t[0]}</b><small>${t[1]}</small></span></label>`).join('');dayPct.textContent=s.pct+'%';dayBar.style.width=s.pct+'%';todayMoney.textContent=state.money[today()]?money(10):'R$ 0';missionText.textContent=s.complete?'Missão completa. Peça aprovação.':'Complete tudo para liberar R$ 10.';tasksDone.textContent=s.done+'/'+s.total}
function renderEagleMessage(){let s=stats(),p=plan(new Date());eagleMessage.textContent=`Prioridade atual: ${smartPriority()}. Hoje é dia de ${p[1]}. Faltam ${Math.max(0,s.total-s.done)} tarefa(s).`}
function buildKnowledge(){return `Projeto Águia V23\nNotas: ${JSON.stringify(state.grades)}\nPrioridade: ${smartPriority()}\nDesempenho academia: ${JSON.stringify(state.academyStats)}\nCatecismo: ${cateDoneCount()}/52\nXP: ${state.xp}`;}
function generateAIPlan(){let pr=smartPriority();state.aiPlan=`${buildKnowledge()}\n\nCrie um plano curto para hoje priorizando ${pr} e inclua 3 exercícios.`;save()}
function renderAI(){if(!state.aiPlan)generateAIPlan();aiPrompt.value=state.aiPlan;critical.textContent=smartPriority()}
function localAI(q){q=(q||'').toLowerCase();let c=smartPriority();if(aiMode.value==='online')return 'Modo online: copie a base de conhecimento e cole em uma IA externa. Para API real, use backend seguro.';if(q.includes('nota')||q.includes('boletim'))return `As notas estão sincronizadas com o responsável. Prioridade atual: ${c}.`;if(q.includes('academia'))return `Na Academia, recomendo responder perguntas de ${c} primeiro. O app evita repetir questões já vistas.`;return `Minha recomendação: comece por ${c}, responda 3 perguntas da Academia e revise seus erros.`}
function renderChallenge(){showQuestion(smartPriority(), challenge)}
function pickQuestion(sub){let bank=questionBank[sub]||[];state.seenQuestions[sub]=state.seenQuestions[sub]||[];let unseen=bank.map((_,i)=>i).filter(i=>!state.seenQuestions[sub].includes(i));if(unseen.length===0){state.seenQuestions[sub]=[];unseen=bank.map((_,i)=>i)}let idx=unseen[Math.floor(Math.random()*unseen.length)];state.seenQuestions[sub].push(idx);save();return {q:bank[idx],idx}}
function showQuestion(sub,target){target=target||quiz;let picked=pickQuestion(sub),q=picked.q;if(!q)return;target.innerHTML=`<h3>${icons[sub]||'📚'} ${sub}</h3><p><b>Pergunta nova:</b> ${q[0]}</p><small>Tema: ${q[4]||'Geral'}</small>`+q[1].map((a,i)=>`<button class="answer" data-sub="${sub}" data-qi="${picked.idx}" data-i="${i}">${a}</button>`).join('')+`<div class="feedback hidden"></div>`}
function renderAnnual(){let y=new Date().getFullYear();let names=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];annualCalendar.innerHTML=`<div class="annual-grid">`+names.map((name,m)=>{let first=new Date(y,m,1),last=new Date(y,m+1,0);let heads=['D','S','T','Q','Q','S','S'].map(x=>`<div class="head">${x}</div>`).join('');let cells='';for(let i=0;i<first.getDay();i++)cells+='<button class="mini-day empty"></button>';for(let day=1;day<=last.getDate();day++){let d=new Date(y,m,day),p=plan(d),key=iso(d),done=state.cateDone[key]?' ✅':'';cells+=`<button class="mini-day ${p[2]}" data-annual="${key}">${day}${done}</button>`}return `<div class="month-card"><h3>${name}</h3><div class="mini-grid">${heads}${cells}</div></div>`}).join('')+`</div>`}
function describeDate(key){let d=new Date(key+'T00:00:00'),p=plan(d),idx=saturdaysOfYear().findIndex(x=>iso(x)===key);let extra=d.getDay()===6?`<br><b>Catecismo:</b> Lição ${idx+1}<br><button data-open-date-cate="${key}">Abrir lição</button>`:'';annualDetails.innerHTML=`<b>${p[0]} — ${key}</b><br><small>Eixo: ${p[1]}</small>${extra}`}
function renderCateReader(){let i=state.catePage||0,l=cateLessons[i],sats=saturdaysOfYear(),key=iso(sats[i]);let fav=state.cateFavorites.includes(i);cateReader.innerHTML=`<div class="reader"><h3>Lição ${i+1}: ${l.theme}</h3><small>Sábado: ${key} • bloco: ${l.range}</small><div class="reader-body">${l.html}</div><div class="reader-controls"><button id="prevCate" class="secondary">◀ Anterior</button><button id="nextCate">Próxima ▶</button><button id="favCate" class="secondary">${fav?'★ Remover favorito':'☆ Favoritar'}</button><button id="markCate">☑ Concluir leitura</button></div></div>`}
function renderCatechism(){let done=cateDoneCount(),pct=Math.round(done/52*100);cateProgress.textContent=pct+'%';cateDone.textContent=done+'/52';cateXP.textContent=state.cateXP+' XP';cateBar.style.width=pct+'%';cateMedal.textContent=done>=52?'Águia da Fé':done>=25?'Discípulo de São Pio X':done>=10?'Pequeno Catequista':'Primeiro Sábado';renderCateReader();renderCateSearch();renderCateFavorites();let current=state.catePage||cateWeekIndex();cateSchedule.innerHTML=saturdaysOfYear().map((d,i)=>`<div class="cate-week ${state.cateDone[iso(d)]?'done':''} ${i===current?'current':''}"><b>Lição ${i+1} — ${iso(d)}</b><br><small>${cateLessons[i].theme}</small><br><button data-open-cate="${i}">Abrir lição</button></div>`).join('');parentCatechism.innerHTML=`<div class="details"><b>${done}/52 sábados</b><br><small>${pct}% concluído • ${state.cateXP} XP</small></div>`}
function renderCateSearch(){let q=(cateSearch.value||'').toLowerCase();if(!q){cateSearchResults.innerHTML='<p class="muted">Digite uma palavra para buscar.</p>';return}let results=cateLessons.map((l,i)=>({t:l.theme,html:l.html,i})).filter(x=>x.t.toLowerCase().includes(q)||x.html.toLowerCase().includes(q));cateSearchResults.innerHTML=results.slice(0,20).map(r=>`<div class="search-result"><b>Lição ${r.i+1}: ${r.t}</b><br><button data-open-cate="${r.i}">Abrir</button></div>`).join('')||'<p class="muted">Nenhum resultado.</p>'}
function renderCateFavorites(){cateFavorites.innerHTML=state.cateFavorites.length?state.cateFavorites.map(i=>`<div class="favorite"><b>Lição ${i+1}: ${cateLessons[i].theme}</b><br><button data-open-cate="${i}">Abrir</button></div>`).join(''):'<p class="muted">Nenhum favorito ainda.</p>'}
function renderAcademy(){let pr=smartPriority();academyPriority.innerHTML=`<b>Prioridade inteligente:</b> ${icons[pr]||'📚'} ${pr}<br><small>Calculada pelas notas do boletim e desempenho na Academia.</small>`;curriculum.innerHTML=Object.entries(curriculum).map(([s,it])=>`<div class="item"><b>${icons[s]||'📚'} ${s}</b><br><small>${it.join(' • ')}</small></div>`).join('');subjects.innerHTML=subjects.map(s=>`<button class="subject ${s===pr?'priority':''}" data-subject="${s}">${icons[s]||'📚'} ${s}</button>`).join('');renderAcademyStats()}
function normalizeGrade(x){x=String(x).replace(',','.');let n=parseFloat(x);if(isNaN(n))return null;if(n>10&&n<=100)n=n/10;return Math.max(0,Math.min(10,n))}
function parseGradesFromText(text){let found={};let norm=text.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();for(let [alias,sub] of Object.entries(aliases)){let a=alias.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();let idx=norm.indexOf(a);if(idx>=0){let slice=text.slice(Math.max(0,idx-20),idx+180);let nums=[...slice.matchAll(/\b(10(?:[,.]0)?|[0-9](?:[,.][0-9])?)\b/g)].map(m=>normalizeGrade(m[1])).filter(v=>v!==null);if(nums.length)found[sub]=nums.slice(0,4)}}return found}
function applyDetectedGrades(found){let count=0;for(let [s,nums] of Object.entries(found)){if(!state.grades[s])state.grades[s]=[0,0,0,0];for(let i=0;i<Math.min(4,nums.length);i++){state.grades[s][i]=nums[i];count++}}save();renderGradesTable();return count}
function renderGradesTable(){let b=['1º bim.','2º bim.','3º bim.','4º bim.'];gradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th>${b.map(x=>`<th>${x}</th>`).join('')}<th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([sub,arr])=>`<tr><td><b>${sub}</b></td>${[0,1,2,3].map(i=>`<td><input data-grade-sub="${sub}" data-grade-i="${i}" type="number" min="0" max="10" step="0.1" value="${arr[i]||0}"></td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`;renderParentGrades();renderAcademy()}
function renderParentGrades(){parentGradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th><th>1º</th><th>2º</th><th>3º</th><th>4º</th><th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([s,arr])=>`<tr><td><b>${s}</b></td>${arr.map(n=>`<td>${Number(n||0).toFixed(1)}</td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`}
function renderAcademyStats(){let html=subjects.map(s=>{let v=state.academyStats[s]||{correct:0,total:0};let pct=v.total?Math.round(v.correct/v.total*100):0;return `<div class="stat-card"><b>${icons[s]||'📚'} ${s}</b><br><small>${v.correct}/${v.total} acertos • ${pct}%</small></div>`}).join('');academyStats.innerHTML=`<div class="grid">${html}</div>`;parentAcademyStats.innerHTML=`<div class="grid">${html}</div>`}
function renderAchievements(){let missions=Object.keys(state.money).length,done=cateDoneCount(),xpVal=state.xp;let a=[['🥉 Primeira missão',missions>=1],['✝️ Primeiro Sábado',done>=1],['📖 Pequeno Catequista',done>=10],['🏛 Discípulo de São Pio X',done>=25],['🦅 Águia da Fé',done>=52]];achievementList.innerHTML=a.map(x=>`<div class="achievement ${x[1]?'done':''}"><b>${x[0]}</b></div>`).join('');campaignMap.innerHTML=['Aspirante','Escudeiro','Estudioso','Discípulo','Águia Jovem','Guardião','Águia Imperial'].map((n,i)=>`<div class="campaign-step ${xpVal>=i*50?'done':''}"><b>${i+1}. ${n}</b></div>`).join('')}
function renderJourney(){let i=state.journeyIndex||0,p=journeyPages[i];journeyContent.innerHTML=`<div class="journey-slide"><div class="journey-emoji">${p.emoji}</div><h3>${p.title}</h3><p>${p.text}</p><small>${i+1} de ${journeyPages.length}</small></div>`;journeyPrev.disabled=i===0;journeyNext.textContent=i===journeyPages.length-1?'Começar 🚀':'Próximo ▶'}
function approve(){let s=stats();if(!s.complete){approval.textContent='A missão ainda não está completa.';return}if(state.money[today()]){approval.textContent='Missão já aprovada hoje.';return}state.money[today()]=10;state.xp+=10;state.piggy.free+=7;state.piggy.saved+=2;state.piggy.charity+=1;state.aiPlan='';save();approval.textContent='🦅 Missão aprovada. R$ 10 liberados.';renderAll()}
function renderAll(){renderMission();renderEagleMessage();renderAI();renderAnnual();renderCatechism();renderAcademy();renderGradesTable();renderAcademyStats();renderAchievements();renderJourney();weekMoney.textContent=money(weekMoneyTotal());xp.textContent=state.xp+' XP'}
async function runOCR(file){ocrStatus.textContent='Processando arquivo...';let url=URL.createObjectURL(file);reportPreview.innerHTML=file.type.includes('pdf')?`<iframe src="${url}"></iframe>`:`<img src="${url}" alt="Boletim">`;if(file.type.startsWith('image/') && window.Tesseract){ocrStatus.textContent='Lendo imagem com OCR. Isso pode demorar...';let res=await Tesseract.recognize(file,'por+eng');ocrText.value=res.data.text;state.lastOCR=res.data.text;save();ocrStatus.textContent='OCR concluído. Revise o texto e clique em detectar notas.';return}ocrStatus.textContent='Arquivo carregado. Para OCR automático, prefira imagem nítida do boletim.'}
document.addEventListener('change',e=>{if(e.target.matches('#tasks input')){state.checked[e.target.dataset.id]=e.target.checked;state.aiPlan='';save();renderAll()}if(e.target.matches('[data-grade-sub]')){let s=e.target.dataset.gradeSub,i=Number(e.target.dataset.gradeI);state.grades[s][i]=Number(e.target.value||0);save();renderGradesTable();}if(e.target.id==='reportFile'){let file=e.target.files[0];if(file)runOCR(file)}if(e.target.id==='importGrades'){let file=e.target.files[0];if(!file)return;let r=new FileReader();r.onload=()=>{try{state.grades=JSON.parse(r.result);save();renderGradesTable();alert('Boletim importado.')}catch(e){alert('Arquivo inválido.')}};r.readAsText(file)}});
document.addEventListener('input',e=>{if(e.target.id==='cateSearch')renderCateSearch()});
document.addEventListener('click',e=>{if(e.target.matches('[data-tab]'))switchTab(e.target.dataset.tab);if(e.target.id==='goParent')switchTab('parent');if(e.target.id==='approve')approve();if(e.target.id==='runAI'){generateAIPlan();renderAll()}if(e.target.id==='copyAIPrompt'){aiPrompt.select();document.execCommand('copy');alert('Relatório copiado.')}if(e.target.id==='copyKnowledge'){navigator.clipboard.writeText(buildKnowledge());alert('Base copiada.')}if(e.target.id==='askLocalAI'){localAIAnswer.textContent=localAI(localAIQuestion.value)}if(e.target.id==='parseGrades'){let found=parseGradesFromText(ocrText.value);let count=applyDetectedGrades(found);parseResult.innerHTML=count?`Notas detectadas e aplicadas: ${count}. Revise a tabela.`:'Nenhuma nota detectada automaticamente. Revise o texto ou preencha manualmente.'}if(e.target.id==='resetQuestionHistory'){state.seenQuestions={};save();alert('Histórico reiniciado.')}if(e.target.id==='smartQuestion'){showQuestion(smartPriority());}if(e.target.matches('[data-annual]'))describeDate(e.target.dataset.annual);if(e.target.matches('[data-open-date-cate]')){let key=e.target.dataset.openDateCate;let idx=saturdaysOfYear().findIndex(d=>iso(d)===key);state.catePage=idx>=0?idx:cateWeekIndex(new Date(key+'T00:00:00'));save();switchTab('catechism')}if(e.target.matches('[data-open-cate]')){state.catePage=Number(e.target.dataset.openCate);state.aiPlan='';save();switchTab('catechism')}if(e.target.matches('[data-subject]'))showQuestion(e.target.dataset.subject);if(e.target.matches('.answer')){let sub=e.target.dataset.sub,q=questionBank[sub][Number(e.target.dataset.qi)],ok=Number(e.target.dataset.i)===q[2];e.target.classList.add(ok?'correct':'wrong');state.xp+=ok?5:0;state.academyStats[sub]=state.academyStats[sub]||{correct:0,total:0};state.academyStats[sub].total++;if(ok)state.academyStats[sub].correct++;let fb=e.target.parentElement.querySelector('.feedback');fb.classList.remove('hidden');fb.textContent=ok?'✅ Correto! +5 XP':'❌ '+q[3];save();renderAcademyStats();}if(e.target.id==='continueCatechism'){state.catePage=cateWeekIndex();save();switchTab('catechism')}if(e.target.id==='prevCate'){state.catePage=Math.max(0,(state.catePage||0)-1);save();renderAll()}if(e.target.id==='nextCate'){state.catePage=Math.min(51,(state.catePage||0)+1);save();renderAll()}if(e.target.id==='favCate'){let i=state.catePage||0;state.cateFavorites=state.cateFavorites.includes(i)?state.cateFavorites.filter(x=>x!==i):[...state.cateFavorites,i];save();renderAll()}if(e.target.id==='markCate'){let i=state.catePage||0,key=iso(saturdaysOfYear()[i]);if(!state.cateDone[key]){state.cateDone[key]=true;state.cateXP+=10;state.xp+=10;save()}renderAll()}if(e.target.id==='journeyNext'){if(state.journeyIndex<journeyPages.length-1){state.journeyIndex++;save();renderJourney()}else switchTab('today')}if(e.target.id==='journeyPrev'){if(state.journeyIndex>0){state.journeyIndex--;save();renderJourney()}}if(e.target.id==='restartJourney'){state.journeyIndex=0;save();renderJourney()}if(e.target.id==='saveGrades'){save();alert('Notas salvas e sincronizadas com o responsável.')}if(e.target.id==='exportGrades'){let blob=new Blob([JSON.stringify(state.grades,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='boletim-projeto-aguia.json';a.click()}if(e.target.id==='export'){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='projeto-aguia-v23-progresso.json';a.click()}if(e.target.id==='logout'){localStorage.removeItem('unlockedV23');location.reload()}});
if('serviceWorker' in navigator)navigator.serviceWorker.register('service-worker.js');
renderAll();
